MAP
  NAME                      "Ontplofbare Oorlogsresten"
  INCLUDE                   "header.inc"
  
  WEB
    METADATA
      "team"                "SOEB"
      "ows_title"           "Ontplofbare Oorlogsresten"
      "ows_abstract"        "Informatie over bominslagen, gevrijwaarde gebieden, verdachte gebieden en uitgevoerde onderzoeken"
      "auth"                "OPENBAAR"
    END
  END


  LAYER
    NAME                    "Blindganger"
    GROUP                   "inslagen"
    INCLUDE                 "connection/dataservices.inc"
    DATA                    "geometrie FROM (select * from public.ontplofbare_oorlogsresten_inslagen_v1 WHERE soort_handeling = 'Blindganger') as subquery USING UNIQUE id USING SRID=28992"
    TYPE                    POINT
    TEMPLATE                "fooOnlyForWMSGetFeatureInfo.html"
    PROJECTION
      "init=epsg:28992"
    END
    METADATA
      "ows_title"           "Blindganger"
      "ows_abstract"        "Informatie over bominslagen, gevrijwaarde gebieden, verdachte gebieden en uitgevoerde onderzoeken"
      "wms_group_title"     "Inslagen"
      "gml_featureid"       "id"
      "gml_geometries"      "geometry"
      "gml_geometry_type"   "point"
      "gml_include_items"   "all"
      "gml_types"           "auto"
      "wms_include_items"   "all"
    END
    CLASS
      NAME                  "blindganger"
      TITLE                 "Blindganer"
    STYLE
        SYMBOL              "stip"
        COLOR               "#e31a1c"
        SIZE                9
      END

      STYLE
        SYMBOL              "kruis"
        COLOR               "#fffff0"
	    ANGLE               45.0
        SIZE                10
      END
    END
  END

