  LAYER
    NAME                    "vermoedelijke_bominslagen"
    GROUP                   "inslagen"
    INCLUDE                 "connection/dataservices.inc"
    DATA                    "geometrie FROM
                              (SELECT *
                              FROM public.ontplofbare_oorlogsresten_inslagen_v1
                              WHERE soort_handeling IN (
                                  'Vermoedelijke bominslag(en)',
                                  'Vermoedelijke inslag',
                                  'Beschadiging door inslag',
                                  'Duidelijke inslag',
                                  'Mogelijke inslag',
                                  'Krater',
                                  'Bominslag')) as subquery USING UNIQUE id USING SRID=28992"
    TYPE                    POINT
    TEMPLATE                "fooOnlyForWMSGetFeatureInfo.html"
    PROJECTION
      "init=epsg:28992"
    END
    METADATA
      "ows_title"           "Vermoedelijke bominslagen"
      "ows_abstract"        "Informatie over bominslagen, gevrijwaarde gebieden, verdachte gebieden en uitgevoerde onderzoeken"
      "wms_group_title"     "Inslagen"
      "gml_featureid"       "id"
      "gml_geometries"      "geometry"
      "gml_geometry_type"   "point"
      "gml_include_items"   "all"
      "gml_types"           "auto"
      "wms_include_items"   "all"
    END
    CLASS
      NAME                  "vermoedelijke_bominslagen"
      TITLE                 "Vermoedelijke bominslagen"
      STYLE
        SYMBOL              "driehoek"
        COLOR               "#e69800"
        SIZE                9
      END
    END
  END

  ##### Verdachte gebieden group

  LAYER
    NAME                    "munities_en_granaten"
    GROUP                   "verdachte_gebieden"
    INCLUDE                 "connection/dataservices.inc"
    DATA                    "geometrie from 
                            ( SELECT * FROM public.ontplofbare_oorlogsresten_verdachte_gebieden_v1 WHERE hoofdgroep = 'Geschutmunitie, Kleinkalibermunitie, Munitietoebehoren, Handgranaten, Geweergranaten, Ontstekingsinrichtingen, Munitie voor granaatwerpers')
                            as subquery USING UNIQUE id
                            USING SRID=28992"
    TYPE                    POLYGON
    TEMPLATE                "fooOnlyForWMSGetFeatureInfo.html"
    PROJECTION
      "init=epsg:28992"
    END
    METADATA
      "ows_title"           "Munities en granaten"
      "ows_abstract"        "Informatie over bominslagen, gevrijwaarde gebieden, verdachte gebieden en uitgevoerde onderzoeken"
      "wms_group_title"     "Verdachte gebieden"
      "gml_featureid"       "id"
      "gml_geometries"      "geometry"
      "gml_geometry_type"   "multipolygon"
      "gml_include_items"   "all"
      "gml_types"           "auto"
      "wms_include_items"   "all"
    END
    CLASS
      NAME                  "munities_en_granaten"
      TITLE                 "Munities en granaten"
      STYLE
        ANTIALIAS           true
        COLOR               "#F5A623"
        OPACITY             20
      END
      STYLE
        OUTLINECOLOR        "#F5A623"
        WIDTH               2
      END
    END
  END

